void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("Maracaibo_fortCommander_1", GetFullName(npchar));			link.l1 = StringFromKey("Maracaibo_fortCommander_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("Maracaibo_fortCommander_3");			link.l1 = StringFromKey("Maracaibo_fortCommander_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("Maracaibo_fortCommander_5");			link.l1 = StringFromKey("Maracaibo_fortCommander_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("Maracaibo_fortCommander_7");			link.l1 = StringFromKey("Maracaibo_fortCommander_8");			link.l1.go = "4";		break;		case "4":			dialog.text = "...";			link.l1 = StringFromKey("Maracaibo_fortCommander_9");			link.l1.go = "5";		break;		case "5":			dialog.text = StringFromKey("Maracaibo_fortCommander_10");			link.l1 = "...";			link.l1.go = "exit";		break;		case "":			dialog.text = "";			link.l1 = "";			link.l1.go = "";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}